```python
"""
Tests for DELETE /onboarding-tasks/{task_id} endpoint.

Requirement: An authenticated system-admin shall be able to delete an
onboarding-task through the REST API. Mandatory fields must be validated
and an audit record must be written on success.
"""

import pytest
from unittest.mock import MagicMock, patch, call
from uuid import uuid4
from datetime import datetime, timezone

# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

VALID_TASK_ID = str(uuid4())
NONEXISTENT_TASK_ID = str(uuid4())
INVALID_TASK_ID = "not-a-valid-uuid"

SYSTEM_ADMIN_TOKEN = "Bearer valid-system-admin-token"
NON_ADMIN_TOKEN = "Bearer valid-non-admin-token"
EXPIRED_TOKEN = "Bearer expired-token"
MALFORMED_TOKEN = "this-is-not-a-bearer-token"

SAMPLE_ONBOARDING_TASK = {
    "id": VALID_TASK_ID,
    "title": "Complete security training",
    "description": "Finish the mandatory security awareness training.",
    "assignee_id": str(uuid4()),
    "due_date": "2024-12-31",
    "status": "pending",
    "created_at": "2024-01-01T00:00:00Z",
    "updated_at": "2024-01-01T00:00:00Z",
}

SAMPLE_SYSTEM_ADMIN = {
    "id": str(uuid4()),
    "username": "admin_user",
    "role": "system-admin",
}


@pytest.fixture
def client(app):
    """Return a test client for the Flask/FastAPI application."""
    return app.test_client()


@pytest.fixture
def mock_task_repository():
    """Mock the onboarding-task data-access layer."""
    with patch("app.repositories.onboarding_task_repository") as mock_repo:
        mock_repo.get_by_id.return_value = SAMPLE_ONBOARDING_TASK
        mock_repo.delete.return_value = True
        yield mock_repo


@pytest.fixture
def mock_audit_service():
    """Mock the audit-logging service."""
    with patch("app.services.audit_service") as mock_audit:
        mock_audit.write.return_value = True
        yield mock_audit


@pytest.fixture
def mock_auth_service():
    """Mock the authentication / authorisation service."""
    with patch("app.services.auth_service") as mock_auth:
        mock_auth.decode_token.return_value = SAMPLE_SYSTEM_ADMIN
        mock_auth.is_system_admin.return_value = True
        yield mock_auth


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def delete_task(client, task_id, token=SYSTEM_ADMIN_TOKEN, **kwargs):
    """Convenience wrapper for the DELETE endpoint."""
    headers = {"Authorization": token}
    headers.update(kwargs.pop("extra_headers", {}))
    return client.delete(f"/api/v1/onboarding-tasks/{task_id}", headers=headers, **kwargs)


# ===========================================================================
# 1. Authentication Tests
# ===========================================================================

class TestAuthentication:
    """The request must carry a valid, non-expired credential."""

    def test_missing_authorization_header_returns_401(
        self, client, mock_task_repository, mock_audit_service
    ):
        response = client.delete(f"/api/v1/onboarding-tasks/{VALID_TASK_ID}")
        assert response.status_code == 401

    def test_malformed_token_returns_401(
        self, client, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, VALID_TASK_ID, token=MALFORMED_TOKEN)
        assert response.status_code == 401

    def test_expired_token_returns_401(
        self, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        mock_auth_service.decode_token.side_effect = TokenExpiredError("Token expired")
        response = delete_task(client, VALID_TASK_ID, token=EXPIRED_TOKEN)
        assert response.status_code == 401

    def test_invalid_signature_token_returns_401(
        self, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        mock_auth_service.decode_token.side_effect = InvalidTokenError("Bad signature")
        response = delete_task(client, VALID_TASK_ID, token="Bearer tampered-token")
        assert response.status_code == 401

    def test_unauthenticated_request_does_not_delete_task(
        self, client, mock_task_repository, mock_audit_service
    ):
        client.delete(f"/api/v1/onboarding-tasks/{VALID_TASK_ID}")
        mock_task_repository.delete.assert_not_called()

    def test_unauthenticated_request_does_not_write_audit_record(
        self, client, mock_task_repository, mock_audit_service
    ):
        client.delete(f"/api/v1/onboarding-tasks/{VALID_TASK_ID}")
        mock_audit_service.write.assert_not_called()


# ===========================================================================
# 2. Authorisation Tests
# ===========================================================================

class TestAuthorisation:
    """Only users with the 'system-admin' role may delete onboarding-tasks."""

    def test_non_admin_role_returns_403(
        self, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        mock_auth_service.is_system_admin.return_value = False
        mock_auth_service.decode_token.return_value = {
            **SAMPLE_SYSTEM_ADMIN,
            "role": "standard-user",
        }
        response = delete_task(client, VALID_TASK_ID, token=NON_ADMIN_TOKEN)
        assert response.status_code == 403

    @pytest.mark.parametrize("role", ["viewer", "editor", "manager", "support"])
    def test_non_system_admin_roles_are_forbidden(
        self, role, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        mock_auth_service.is_system_admin.return_value = False
        mock_auth_service.decode_token.return_value = {
            **SAMPLE_SYSTEM_ADMIN,
            "role": role,
        }
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 403

    def test_forbidden_request_does_not_delete_task(
        self, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        mock_auth_service.is_system_admin.return_value = False
        delete_task(client, VALID_TASK_ID, token=NON_ADMIN_TOKEN)
        mock_task_repository.delete.assert_not_called()

    def test_forbidden_request_does_not_write_audit_record(
        self, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        mock_auth_service.is_system_admin.return_value = False
        delete_task(client, VALID_TASK_ID, token=NON_ADMIN_TOKEN)
        mock_audit_service.write.assert_not_called()

    def test_system_admin_role_is_permitted(
        self, client, mock_task_repository, mock_audit_service, mock_auth_service
    ):
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 204


# ===========================================================================
# 3. Mandatory Field Validation Tests
# ===========================================================================

class TestMandatoryFieldValidation:
    """The task_id path parameter is mandatory and must be a valid UUID."""

    def test_missing_task_id_returns_404_or_405(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        # Route does not exist without the task_id segment
        response = client.delete(
            "/api/v1/onboarding-tasks/",
            headers={"Authorization": SYSTEM_ADMIN_TOKEN},
        )
        assert response.status_code in (404, 405)

    def test_invalid_uuid_format_returns_422(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, INVALID_TASK_ID)
        assert response.status_code == 422

    def test_invalid_uuid_returns_descriptive_error(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, INVALID_TASK_ID)
        body = response.get_json()
        assert "task_id" in str(body).lower() or "invalid" in str(body).lower()

    def test_empty_string_task_id_returns_422_or_404(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, "")
        assert response.status_code in (404, 422)

    def test_sql_injection_in_task_id_is_rejected(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, "1; DROP TABLE onboarding_tasks;--")
        assert response.status_code in (400, 422)

    def test_invalid_task_id_does_not_call_repository(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, INVALID_TASK_ID)
        mock_task_repository.delete.assert_not_called()

    def test_invalid_task_id_does_not_write_audit_record(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, INVALID_TASK_ID)
        mock_audit_service.write.assert_not_called()


# ===========================================================================
# 4. Successful Deletion Tests
# ===========================================================================

class TestSuccessfulDeletion:
    """Happy-path: authenticated system-admin deletes an existing task."""

    def test_returns_204_no_content(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 204

    def test_response_body_is_empty(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        response = delete_task(client, VALID_TASK_ID)
        assert response.data == b"" or response.get_json() is None

    def test_repository_delete_called_with_correct_task_id(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        mock_task_repository.delete.assert_called_once_with(VALID_TASK_ID)

    def test_task_no_longer_retrievable_after_deletion(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        mock_task_repository.get_by_id.return_value = None
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 404


# ===========================================================================
# 5. Audit Record Tests
# ===========================================================================

class TestAuditRecord:
    """An audit record MUST be written on every successful deletion."""

    def test_audit_service_called_on_success(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        mock_audit_service.write.assert_called_once()

    def test_audit_record_contains_correct_action(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        audit_kwargs = mock_audit_service.write.call_args
        action = _extract_audit_field(audit_kwargs, "action")
        assert action in ("DELETE", "delete", "DELETED", "onboarding_task.deleted")

    def test_audit_record_contains_task_id(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        audit_kwargs = mock_audit_service.write.call_args
        resource_id = _extract_audit_field(audit_kwargs, "resource_id")
        assert resource_id == VALID_TASK_ID

    def test_audit_record_contains_actor_id(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        audit_kwargs = mock_audit_service.write.call_args
        actor_id = _extract_audit_field(audit_kwargs, "actor_id")
        assert actor_id == SAMPLE_SYSTEM_ADMIN["id"]

    def test_audit_record_contains_timestamp(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        before = datetime.now(timezone.utc)
        delete_task(client, VALID_TASK_ID)
        after = datetime.now(timezone.utc)

        audit_kwargs = mock_audit_service.write.call_args
        timestamp = _extract_audit_field(audit_kwargs, "timestamp")

        if isinstance(timestamp, str):
            timestamp = datetime.fromisoformat(timestamp)
        assert before <= timestamp <= after

    def test_audit_record_contains_resource_type(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        audit_kwargs = mock_audit_service.write.call_args
        resource_type = _extract_audit_field(audit_kwargs, "resource_type")
        assert "onboarding" in resource_type.lower() or "task" in resource_type.lower()

    def test_audit_record_not_written_when_task_not_found(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_task_repository.get_by_id.return_value = None
        delete_task(client, NONEXISTENT_TASK_ID)
        mock_audit_service.write.assert_not_called()

    def test_audit_record_not_written_when_unauthenticated(
        self, client, mock_task_repository, mock_audit_service
    ):
        client.delete(f"/api/v1/onboarding-tasks/{VALID_TASK_ID}")
        mock_audit_service.write.assert_not_called()

    def test_audit_record_not_written_when_forbidden(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_auth_service.is_system_admin.return_value = False
        delete_task(client, VALID_TASK_ID, token=NON_ADMIN_TOKEN)
        mock_audit_service.write.assert_not_called()

    def test_audit_record_not_written_when_validation_fails(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, INVALID_TASK_ID)
        mock_audit_service.write.assert_not_called()

    def test_deletion_rolls_back_if_audit_write_fails(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        """Atomicity: if the audit write fails the delete should not persist."""
        mock_audit_service.write.side_effect = AuditServiceUnavailableError
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 500
        mock_task_repository.delete.assert_called_once()
        # Verify compensating transaction / rollback was triggered
        mock_task_repository.restore.assert_called_once_with(VALID_TASK_ID)


# ===========================================================================
# 6. Resource-Not-Found Tests
# ===========================================================================

class TestResourceNotFound:
    """Attempting to delete a task that does not exist must return 404."""

    def test_nonexistent_task_returns_404(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_task_repository.get_by_id.return_value = None
        response = delete_task(client, NONEXISTENT_TASK_ID)
        assert response.status_code == 404

    def test_nonexistent_task_returns_descriptive_error(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_task_repository.get_by_id.return_value = None
        response = delete_task(client, NONEXISTENT_TASK_ID)
        body = response.get_json()
        assert body is not None
        assert "not found" in str(body).lower() or "404" in str(body)

    def test_double_delete_returns_404(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        mock_task_repository.get_by_id.return_value = None
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 404


# ===========================================================================
# 7. Idempotency & Concurrency Tests
# ===========================================================================

class TestIdempotencyAndConcurrency:

    def test_repository_delete_called_exactly_once_per_request(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        assert mock_task_repository.delete.call_count == 1

    def test_audit_written_exactly_once_per_successful_request(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        delete_task(client, VALID_TASK_ID)
        assert mock_audit_service.write.call_count == 1


# ===========================================================================
# 8. Error Handling / Infrastructure Tests
# ===========================================================================

class TestErrorHandling:

    def test_repository_failure_returns_500(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_task_repository.delete.side_effect = DatabaseConnectionError("DB down")
        response = delete_task(client, VALID_TASK_ID)
        assert response.status_code == 500

    def test_repository_failure_does_not_write_audit_record(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_task_repository.delete.side_effect = DatabaseConnectionError("DB down")
        delete_task(client, VALID_TASK_ID)
        mock_audit_service.write.assert_not_called()

    def test_500_response_does_not_leak_stack_trace(
        self, client, mock_auth_service, mock_task_repository, mock_audit_service
    ):
        mock_task_repository.delete.side_effect = Exception("Unexpected error")
        response = delete_task(client, VALID_TASK_ID)
        body = response.get_json() or {}
        assert "traceback" not in str(body).lower()
        assert "exception" not in str(body).lower()


# ===========================================================================
# Helper utilities
# ===========================================================================

def _extract_audit_field(call_args, field: str):
    """Extract a named field from either positional or keyword call args."""
    if call_args is None:
        raise AssertionError("audit_service.write was never called")
    args, kwargs = call_args
    if field in kwargs:
        return kwargs[field]
    # Assume first positional arg is a dict payload
    if args and isinstance(args[0], dict):
        return args[0][field]
    raise KeyError(f"Field '{field}' not found in audit call args: {call_args}")


